#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long powmod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1)
            res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

long long comb(long long n, long long k, long long mod) {
    long long num = 1, den = 1;
    for (long long i = 1; i <= k; i++) {
        num = (num * (n - i + 1)) % mod;
        den = (den * i) % mod;
    }
    return (num * powmod(den, mod - 2, mod)) % mod;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, M, R;
        scanf("%lld %lld %lld", &N, &M, &R);
        long long ans = 0;
        for (long long mask = 0; mask < (1 << M); mask++) {
            long long cnt = 0, ways = 1;
            for (long long i = 0; i < M; i++) {
                if (mask & (1 << i))
                    cnt++;
            }
            if (cnt < R || cnt > N)
                continue;
            for (long long i = 0; i < N; i++) {
                ways = (ways * comb(cnt - 1, R - 1, MOD)) % MOD;
            }
            ans = (ans + ways) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

