code.Python3:
import sys
MOD = 1000000007

def powmod(a, b, mod):
    res = 1
    while b > 0:
        if b & 1:
            res = (res * a) % mod
        a = (a * a) % mod
        b >>= 1
    return res

def comb(n, k, mod):
    num = 1
    den = 1
    for i in range(1, k + 1):
        num = (num * (n - i + 1)) % mod
        den = (den * i) % mod
    return (num * powmod(den, mod - 2, mod)) % mod

def main():
    T = int(sys.stdin.readline().strip())
    for _ in range(T):
        N, M, R = map(int, sys.stdin.readline().strip().split())
        ans = 0
        for mask in range(1 << M):
            cnt = 0
            ways = 1
            for i in range(M):
                if mask & (1 << i):
                    cnt += 1
            if cnt < R or cnt > N:
                continue
            for i in range(N):
                ways = (ways * comb(cnt - 1, R - 1, MOD)) % MOD
            ans = (ans + ways) % MOD
        print(ans)
if __name__ == '__main__':
    main()

